export type ParsedResolveDisputeInstruction<
  TProgram extends string = typeof TENDER_PROGRAM_ADDRESS,
  TAccountMetas extends readonly AccountMeta[] = readonly AccountMeta[],
> = {
  programAddress: Address<TProgram>;
  accounts: {
    party: TAccountMetas[0];
    rfp: TAccountMetas[1];
    milestone: TAccountMetas[2];
    escrow: TAccountMetas[3];
    mint: TAccountMetas[4];
    escrowAta: TAccountMetas[5];
    providerAta: TAccountMetas[6];
    buyerAta: TAccountMetas[7];
    treasury: TAccountMetas[8];
    treasuryAta: TAccountMetas[9];
    /** Both rep accounts so we can update amount trackers + the dispute counters. */
    buyerReputation: TAccountMetas[10];
    providerReputation: TAccountMetas[11];
    tokenProgram: TAccountMetas[12];
    systemProgram: TAccountMetas[13];
  };
  data: ResolveDisputeInstructionData;
};

export function parseResolveDisputeInstruction<
  TProgram extends string,
  TAccountMetas extends readonly AccountMeta[],
>(
  instruction: Instruction<TProgram> &
    InstructionWithAccounts<TAccountMetas> &
    InstructionWithData<ReadonlyUint8Array>,
): ParsedResolveDisputeInstruction<TProgram, TAccountMetas> {
  if (instruction.accounts.length < 14) {
    throw new SolanaError(
      SOLANA_ERROR__PROGRAM_CLIENTS__INSUFFICIENT_ACCOUNT_METAS,
      {
        actualAccountMetas: instruction.accounts.length,
        expectedAccountMetas: 14,
      },
    );
  }
  let accountIndex = 0;
  const getNextAccount = () => {
    const accountMeta = (instruction.accounts as TAccountMetas)[accountIndex]!;
    accountIndex += 1;
    return accountMeta;
  };
  return {
    programAddress: instruction.programAddress,
    accounts: {
      party: getNextAccount(),
      rfp: getNextAccount(),
      milestone: getNextAccount(),
      escrow: getNextAccount(),
      mint: getNextAccount(),
      escrowAta: getNextAccount(),
      providerAta: getNextAccount(),
      buyerAta: getNextAccount(),
      treasury: getNextAccount(),
      treasuryAta: getNextAccount(),
      buyerReputation: getNextAccount(),
      providerReputation: getNextAccount(),
      tokenProgram: getNextAccount(),
      systemProgram: getNextAccount(),
    },
    data: getResolveDisputeInstructionDataDecoder().decode(instruction.data),
  };
}
